sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    var entityTypeSysId = request.queryParams.entity_type_sys_id;
	var entityTypeName = request.queryParams.entity_type_name;
	var entityTypeLabel = request.queryParams.entity_type_label;

    if (!entityTypeSysId || !entityTypeName || !entityTypeLabel) {
        response.setStatus(400);
        return { error: "entity_type_sys_id, entity_type_name and entity_type_label query parameter is required" };
    }

	if (Array.isArray(entityTypeSysId)) {
		entityTypeSysId = entityTypeSysId[0];
	}

	if (Array.isArray(entityTypeName)) {
		entityTypeName = entityTypeName[0];
	}

	if (Array.isArray(entityTypeLabel)) {
		entityTypeLabel = entityTypeLabel[0];
	}

    // Step 1: Get the table name from sys_db_object
    var dbObject = new GlideRecord('sys_db_object');
    dbObject.addQuery('sys_id', entityTypeSysId);
	dbObject.addQuery('name', entityTypeName);
	dbObject.addQuery('label', entityTypeLabel);
    dbObject.query();
    if (!dbObject.next()) {
        response.setStatus(404);
        return { error: "Entity not found" };
    }

    // Step 2: Build the hierarchy chain (child -> parent -> grandparent -> ...)
    var tableChain = [];
    var currentTable = entityTypeName;
    var maxDepth = 50; // Safety limit to prevent infinite loops

    while (currentTable && maxDepth > 0) {
        tableChain.push(currentTable);
        maxDepth--;

        // Look up the parent (super_class) of the current table
        var parentObj = new GlideRecord('sys_db_object');
        parentObj.addQuery('name', currentTable);
        parentObj.query();
        if (parentObj.next() && parentObj.getValue('super_class')) {
            var parentRef = new GlideRecord('sys_db_object');
            parentRef.addQuery('sys_id', parentObj.getValue('super_class'));
            parentRef.query();
            if (parentRef.next()) {
                currentTable = parentRef.getValue('name');
            } else {
                break;
            }
        } else {
            break;
        }
    }

    // Step 3: Find incident fields that reference ANY table in the hierarchy
    var dict = new GlideRecord('sys_dictionary');
    dict.addQuery('name', 'IN', 'incident,task');
    dict.addQuery('reference', 'IN', tableChain.join(','));
    dict.query();

    var fields = [];
    while (dict.next()) {
        fields.push(dict.getValue('element'));
    }

	response.setStatus(200);
    return {
        status: "Success",
        fields: fields
    };

})(request, response);
